<!doctype html><html lang="id"><head><meta charset="utf-8"><title>Kwitansi</title><style>body{font-family:Arial;margin:32px}.receipt{max-width:820px;margin:auto;border:1px solid #ddd;padding:28px}.cancel{font-size:48px;color:#dc2626;border:3px solid #dc2626;text-align:center;transform:rotate(-8deg)}@media print{.no-print{display:none}}</style></head><body><main class="receipt">@if($payment->status === 'cancelled')<div class="cancel">DIBATALKAN</div>@endif<h1>Kwitansi Pembayaran</h1><p>Nomor Kwitansi: {{ $payment->receipt_number ?? $payment->payment_number }}</p><p>Tanggal: {{ $payment->payment_date }}</p><p>Siswa: {{ $payment->student?->name }}</p><p>Metode: {{ str($payment->payment_method)->replace('_',' ')->headline() }}</p><table width="100%">@foreach($payment->allocations as $allocation)<tr><td>{{ $allocation->invoice?->feeType?->name }} ({{ $allocation->invoice?->invoice_number }})</td><td align="right">Rp {{ number_format((int) $allocation->amount, 0, ',', '.') }}</td></tr>@endforeach</table><h2>Total Rp {{ number_format((int) $payment->total_amount, 0, ',', '.') }}</h2><p>Terbilang: {{ ucfirst((new \NumberFormatter('id', \NumberFormatter::SPELLOUT))->format((int)$payment->total_amount)) }} rupiah</p><p>Petugas: {{ $payment->receiver?->name ?? $payment->received_by }}</p><button class="no-print" onclick="window.print()">Cetak</button></main></body></html>
